"use strict";(()=>{async function s(e,n={}){let t=new Headers(n.headers);t.has("accept")||t.set("accept","application/json");let o=await fetch(e,{credentials:"same-origin",...n,headers:t});if(o.status===401)throw location.href="/app/login?next="+encodeURIComponent(location.pathname+location.search),new Error("session expired");return o}function a(e){return e.replace(/[&<>"']/g,n=>({"&":"&amp;","<":"&lt;",">":"&gt;",'"':"&quot;","'":"&#39;"})[n])}async function c(e,n){try{let t=await s("/app/tasks/complete",{method:"POST",headers:{"content-type":"application/json"},body:JSON.stringify({id:e})});if(!t.ok)throw new Error("complete "+t.status);let o=n.parentElement;n.remove(),o&&o.children.length===0&&(o.outerHTML='<p class="home-empty">Nada vencendo nas pr\xF3ximas 24h.</p>')}catch(t){console.warn("home: complete failed",t)}}function l(){document.querySelectorAll(".home-task-complete").forEach(e=>{e.addEventListener("click",()=>{let n=e.dataset.id,t=e.closest("li");n&&t&&c(n,t)})})}function m(e){let n=Date.parse(e.includes("T")?e:`${e.replace(" ","T")}Z`);return Number.isNaN(n)?e:new Date(n).toLocaleString("pt-BR",{timeZone:"America/Sao_Paulo",day:"2-digit",month:"2-digit",hour:"2-digit",minute:"2-digit"})}async function p(){let e=document.getElementById("home-events-list");if(!e)return;let n=e.dataset.limit||"5";try{let t=await s(`/app/contacts/events/recent?limit=${encodeURIComponent(n)}`);if(!t.ok)throw new Error("events "+t.status);let o=await t.json(),r=Array.isArray(o.events)?o.events:[];if(r.length===0){e.innerHTML='<li class="home-empty">Nenhuma intera\xE7\xE3o registrada ainda.</li>';return}e.innerHTML=r.map(i=>`<li>
          <a class="home-event-title" href="${`/app/contacts/${encodeURIComponent(i.entity_id)}`}">${a(i.entity_name||"Contato")}</a>
          <span class="home-event-kind">${a(i.kind)}</span>
          <span class="home-event-when">${a(m(i.ts))}</span>
        </li>`).join("")}catch(t){e.innerHTML='<li class="home-empty home-error">N\xE3o foi poss\xEDvel carregar as intera\xE7\xF5es agora.</li>',console.warn("home: interactions load failed",t)}}l();p();})();
